import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"内在价值","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/内在价值.md","filePath":"05_quotes/by-theme/内在价值.md"}'),r={name:"05_quotes/by-theme/内在价值.md"};function l(q,t,c,_,p,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="内在价值" tabindex="-1">内在价值 <a class="header-anchor" href="#内在价值" aria-label="Permalink to &quot;内在价值&quot;">​</a></h1><blockquote><p>&quot;价格是你付出的，价值是你得到的。&quot;——巴菲特</p></blockquote><p>内在价值是巴菲特投资哲学的核心概念，也是评估一切的起点。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;内在价值是一个企业从现在到清算日能产生的现金流折现值。它不是一个精确的数字，而是一个估计区间。&quot;</p></blockquote><blockquote><p>&quot;在伯克希尔，真正重要的是内在价值，而不是账面价值。我们账面价值与内在价值同步，是因为我们拥有的是真正卓越的企业，而非普通资产。&quot;</p></blockquote><blockquote><p>&quot;内在价值对账面价值的溢价扩大，原因很简单：我们拥有一些卓越的企业，这些企业由更卓越的经理运营。&quot;</p></blockquote><blockquote><p>&quot;长期来看，市场价格会回归内在价值。短期内市场是投票机，长期是称重机。&quot;</p></blockquote><blockquote><p>&quot;投资的第一原则是：不要亏损。第二原则是：不要忘记第一条。避免亏损的方法是，在买入时确保安全边际——即市场价格远低于内在价值。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1967年 · 1987年 · 1996年 · 2000年 · 2012年 · 2020年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
